    public YamlService() {
        this.yamlParser = new Yaml(new SafeConstructor());
    }

    /**
     * Parses user-provided YAML content into a Java object.
     * 
     * @param yamlContent The YAML string to be parsed
     * @return The parsed object representation of the YAML content
     * @throws IllegalArgumentException if the YAML content is invalid or null
     */
    public Object parseUserYaml(String yamlContent) {
        // Check if the input is null
        if (yamlContent == null) {
            throw new IllegalArgumentException("YAML content cannot be null");
        }

        // Check if the input is empty after trimming
        if (yamlContent.trim().isEmpty()) {
            return null; // Return null for empty content
        }

        try {
            // Parse the YAML content using SnakeYAML
            return yamlParser.load(yamlContent);
        } catch (YAMLException e) {
            // Handle any parsing errors
            throw new IllegalArgumentException("Invalid YAML format: " + e.getMessage(), e);
        }
    }
}
